+    if (max >= threshold) {
+      const Vec axis = cross(directions[0][index[0]], dir);
+      qreal angle = asin(axis.norm());
+      if (directions[0][index[0]] * dir >= 0.0)
+        angle = -angle;
+      rotate(rotation().inverse() * Quaternion(axis, angle) * orientation());
+    }
+  }
+
