+    Frame fr(kf->position(), kf->orientation());
+    QDomElement kfNode = fr.domElement("KeyFrame", document);
+    kfNode.setAttribute("index", QString::number(count));
+    kfNode.setAttribute("time", QString::number(kf->time()));
+    de.appendChild(kfNode);
+    ++count;
+  }
