+		TopologicalSortUtils::topologicalSort(precedence_graph, primitive_tab,vparams) ;
+
+#ifdef DEBUG_TS
+	cout << "New order: " ;
+	for(unsigned int i=0;i<primitive_tab.size();++i) cout << (void *)(primitive_tab[i]) << " " ;
+	cout << endl ;
+#endif
+}
