+#ifndef DOXYGEN
+/*! This method has been deprecated in libQGLViewer version 2.2.0 */
+void Camera::drawCamera(float, float, float)
+{
+  qWarning("drawCamera is deprecated. Use Camera::draw() instead.");
+}
