+  const float deltaTime = 0.04; // output a position every deltaTime seconds
+  for (float time=kfi.firstTime(); time<=kfi.lastTime(); time += deltaTime)
+  {
+    kfi.interpolateAtTime(time);
+    cout << "t=" << time << "\tpos=" << kfi.frame()->position() << endl;
+  }
+  \endcode
