+  switch (action_)
+    {
+    case QGLViewer::MOVE_FORWARD:
+    case QGLViewer::MOVE_BACKWARD:
+    case QGLViewer::DRIVE:
+#if QT_VERSION >= 0x040000
+      flyTimer_.setSingleShot(false);
+#endif
+      flyTimer_.start(10);
+      break;
+    default:
+      break;
+    }
+}
+#endif
