+/*! Copy constructor. Performs a deep copy of all attributes using operator=(). */
+ManipulatedFrame::ManipulatedFrame(const ManipulatedFrame& mf)
+  : Frame(mf), MouseGrabber()
+{
+  (*this)=mf;
+}
